import{_ as o,o as t,c as a,a2 as i}from"./chunks/framework.BZO4qERu.js";const m=JSON.parse('{"title":"Codex-to-IM 桥接安全模型","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/security.md","filePath":"architecture/security.md","lastUpdated":1780478520000}'),r={name:"architecture/security.md"};function l(d,e,c,s,n,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="codex-to-im-桥接安全模型" tabindex="-1">Codex-to-IM 桥接安全模型 <a class="header-anchor" href="#codex-to-im-桥接安全模型" aria-label="Permalink to &quot;Codex-to-IM 桥接安全模型&quot;">​</a></h1><h2 id="威胁模型" tabindex="-1">威胁模型 <a class="header-anchor" href="#威胁模型" aria-label="Permalink to &quot;威胁模型&quot;">​</a></h2><p>bridge 会把 IM 平台消息暴露给 LLM。主要风险包括：</p><ol><li><strong>未授权访问</strong>：任何能给 bot 发消息的人都可能获得 LLM 访问能力。</li><li><strong>提示词注入</strong>：恶意内容可以通过 IM 消息进入模型上下文。</li><li><strong>命令注入</strong>：<code>/cwd</code> 等命令中的路径穿越或 shell 元字符可能造成风险。</li><li><strong>拒绝服务</strong>：高频消息可能造成资源耗尽。</li><li><strong>权限绕过</strong>：伪造回调请求或重复点击按钮可能绕过审批语义。</li></ol><h2 id="缓解措施" tabindex="-1">缓解措施 <a class="header-anchor" href="#缓解措施" aria-label="Permalink to &quot;缓解措施&quot;">​</a></h2><h3 id="身份认证与授权" tabindex="-1">身份认证与授权 <a class="header-anchor" href="#身份认证与授权" aria-label="Permalink to &quot;身份认证与授权&quot;">​</a></h3><p>每个 adapter 都实现 <code>isAuthorized(userId, chatId)</code>：</p><ul><li><strong>飞书</strong>：使用已配置的用户白名单、群策略和 mention 检查。</li></ul><p>未授权消息会被静默丢弃，不返回响应，避免泄漏信息。</p><h3 id="输入校验-security-validators-ts" tabindex="-1">输入校验（<code>security/validators.ts</code>） <a class="header-anchor" href="#输入校验-security-validators-ts" aria-label="Permalink to &quot;输入校验（`security/validators.ts`）&quot;">​</a></h3><ul><li><code>validateWorkingDirectory()</code>：拒绝相对路径、<code>..</code> 路径穿越和 shell 元字符（<code>|;&amp;$</code>）。</li><li><code>validateSessionId()</code>：只接受 32-64 字符的 hex/UUID 格式。</li><li><code>isDangerousInput()</code>：检测路径穿越、命令注入、null byte 和控制字符。</li><li><code>sanitizeInput()</code>：移除控制字符（保留 <code>\\n</code>、<code>\\t</code>），并限制最大长度为 10,000 字符。</li><li><code>validateMode()</code>：使用白名单（<code>normal</code>、<code>yolo</code>；<code>code</code> 映射为 <code>normal</code>）。</li></ul><h3 id="限流-security-rate-limiter-ts" tabindex="-1">限流（<code>security/rate-limiter.ts</code>） <a class="header-anchor" href="#限流-security-rate-limiter-ts" aria-label="Permalink to &quot;限流（`security/rate-limiter.ts`）&quot;">​</a></h3><p>采用 token bucket 算法：每个 chat ID 每分钟最多 20 条消息。空闲 bucket 会定期清理。</p><h3 id="权限安全" tabindex="-1">权限安全 <a class="header-anchor" href="#权限安全" aria-label="Permalink to &quot;权限安全&quot;">​</a></h3><ul><li><strong>来源校验</strong>：回调必须来自原始权限提示所在的同一聊天和同一消息 ID。</li><li><strong>原子去重</strong>：<code>markPermissionLinkResolved()</code> 使用原子 check-and-set，防止并发按钮点击造成竞态。</li><li><strong>内存去重</strong>：<code>recentPermissionForwards</code> map 防止 30 秒窗口内重复转发。</li></ul><h3 id="审计日志" tabindex="-1">审计日志 <a class="header-anchor" href="#审计日志" aria-label="Permalink to &quot;审计日志&quot;">​</a></h3><p>所有入站和出站消息都会通过 <code>store.insertAuditLog()</code> 记录：</p><ul><li>通道类型、chat ID、方向、message ID 和截断后的摘要。</li><li>被拦截的危险输入会带 <code>[BLOCKED]</code> 前缀。</li><li>被截断的输入会带 <code>[TRUNCATED]</code> 前缀。</li></ul><h3 id="传输安全" tabindex="-1">传输安全 <a class="header-anchor" href="#传输安全" aria-label="Permalink to &quot;传输安全&quot;">​</a></h3><ul><li>所有平台 API 都使用 HTTPS。</li><li>Bot token 存放在宿主机配置存储中，不写入 bridge 代码。</li><li>UI 中会对 token 做脱敏，降低意外泄漏风险。</li></ul><h2 id="部署建议" tabindex="-1">部署建议 <a class="header-anchor" href="#部署建议" aria-label="Permalink to &quot;部署建议&quot;">​</a></h2><ol><li>始终配置 <code>allowed_users</code>，不要开放给所有人使用。</li><li>bridge 和通知用途使用不同 bot token。</li><li>监控审计日志中的异常模式。</li><li>在运维手册中保留 bot token 轮换流程。</li><li>根据部署环境考虑对宿主应用增加网络层限制，例如防火墙或 VPN。</li></ol>',22)])])}const b=o(r,[["render",l]]);export{m as __pageData,b as default};
